#!/usr/bin/env node
/**
 * OTC-AGT-007 — Delivery Tracking & Confirmation Agent
 * PRODUCTION MIGRATION SCRIPT
 *
 * Reads all platform intelligence created in DEV and recreates it in PROD.
 * Reads dev IDs from: scripts/otc-agt-007-dev-ids.json
 * Saves prod IDs to:  scripts/otc-agt-007-prod-ids.json
 *
 * Usage:
 *   node scripts/migrate-otc-agt-007-to-prod.js
 *
 * Prerequisites:
 *   - scripts/otc-agt-007-dev-ids.json must exist (generated by create-otc-agt-007-dev.js)
 *   - Production environment must be accessible at PROD_BASE URL
 *   - Dev agent reviewed at http://localhost:5000 and approved for migration
 */

import { readFileSync, writeFileSync } from "fs";

const PROD_BASE = "https://audit-dashboard-neilevanfox.replit.app";
const PROD_ORG  = "cf5754b1-ee80-4b51-8bf6-7be263c97527";
const DEV_BASE  = "http://localhost:5000";

// ── HTTP Helpers ──────────────────────────────────────────────────────────────

async function post(base, path, body) {
  const r = await fetch(`${base}${path}`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(body),
  });
  const text = await r.text();
  if (text.startsWith("<!DOCTYPE") || text.startsWith("<html")) {
    throw new Error(`POST ${path} → HTML (route missing?): ${text.slice(0, 200)}`);
  }
  let data;
  try { data = JSON.parse(text); } catch { data = text; }
  if (!r.ok) throw new Error(`POST ${path} → ${r.status}: ${JSON.stringify(data).slice(0, 600)}`);
  return data;
}

async function patch(base, path, body) {
  const r = await fetch(`${base}${path}`, {
    method: "PATCH",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(body),
  });
  const text = await r.text();
  if (text.startsWith("<!DOCTYPE") || text.startsWith("<html")) {
    throw new Error(`PATCH ${path} → HTML: ${text.slice(0, 200)}`);
  }
  let data;
  try { data = JSON.parse(text); } catch { data = text; }
  if (!r.ok) throw new Error(`PATCH ${path} → ${r.status}: ${JSON.stringify(data).slice(0, 600)}`);
  return data;
}

async function get(base, path) {
  const r = await fetch(`${base}${path}`, { headers: { "Content-Type": "application/json" } });
  const text = await r.text();
  if (text.startsWith("<!DOCTYPE") || text.startsWith("<html")) {
    throw new Error(`GET ${path} → HTML`);
  }
  let data;
  try { data = JSON.parse(text); } catch { data = text; }
  if (!r.ok) throw new Error(`GET ${path} → ${r.status}: ${JSON.stringify(data).slice(0, 600)}`);
  return data;
}

const log  = (msg) => console.log(`  ✓  ${msg}`);
const warn = (msg) => console.log(`  ⚠  ${msg}`);
const step = (n, t, msg) => console.log(`\nSTEP ${n}/${t}  ${msg}…`);

// ── Dev data fetchers ──────────────────────────────────────────────────────────

async function getDevSkill(skillId) { return get(DEV_BASE, `/api/skills/${skillId}`); }
async function getDevKB(kbId) { return get(DEV_BASE, `/api/knowledge-bases/${kbId}`); }
async function getDevKBSources(kbId) {
  const res = await get(DEV_BASE, `/api/knowledge-bases/${kbId}/sources`);
  return Array.isArray(res) ? res : (res.sources || []);
}
async function getDevRunbook(rbId) { return get(DEV_BASE, `/api/runbooks/${rbId}`); }
async function getDevPolicy(pId) { return get(DEV_BASE, `/api/policies/${pId}`); }
async function getDevAgent(agentId) { return get(DEV_BASE, `/api/agents/${agentId}`); }
async function getDevEval(evalId) { return get(DEV_BASE, `/api/evals/${evalId}`); }
async function getDevDataset(dsId) { return get(DEV_BASE, `/api/golden-datasets/${dsId}`); }
async function getDevTestCases(dsId) {
  const res = await get(DEV_BASE, `/api/golden-datasets/${dsId}/test-cases`);
  return Array.isArray(res) ? res : (res.testCases || res.cases || []);
}
async function getDevOutcome(outcomeId) { return get(DEV_BASE, `/api/outcomes/${outcomeId}`); }
async function getDevOutcomeKPIs(outcomeId) {
  const res = await get(DEV_BASE, `/api/outcomes/${outcomeId}/kpis`);
  return Array.isArray(res) ? res : (res.kpis || []);
}

// ── MAIN ──────────────────────────────────────────────────────────────────────

async function main() {
  console.log("\n════════════════════════════════════════════════════════════════════");
  console.log("  OTC-AGT-007 — Delivery Tracking & Confirmation Agent");
  console.log("  PRODUCTION MIGRATION SCRIPT");
  console.log(`  Target: ${PROD_BASE}`);
  console.log(`  Org:    ${PROD_ORG}`);
  console.log("════════════════════════════════════════════════════════════════════\n");

  // Load dev IDs
  const devIds = JSON.parse(readFileSync("scripts/otc-agt-007-dev-ids.json", "utf8"));
  console.log(`Loaded dev IDs: agent=${devIds.agentId}, ${devIds.skillIds.length} skills, KB=${devIds.kbId}`);

  const prodIds = {};

  // ── STEP 1: 6 SKILLS ─────────────────────────────────────────────────────────
  step("1", "11", "Migrating 6 skills to PROD");
  prodIds.skillIds = [];
  for (const devSkillId of devIds.skillIds) {
    const devSkill = await getDevSkill(devSkillId);
    const { id, createdAt, updatedAt, ...skillData } = devSkill;
    const prodSkill = await post(PROD_BASE, "/api/skills", {
      ...skillData,
      organizationId: PROD_ORG,
    });
    prodIds.skillIds.push(prodSkill.id);
    log(`Skill → ${devSkill.name.slice(0, 60)} [${prodSkill.id}]`);
  }

  // ── STEP 2: KNOWLEDGE BASE ────────────────────────────────────────────────────
  step("2", "11", "Creating knowledge base in PROD");
  const devKB = await getDevKB(devIds.kbId);
  const { id: kbId, createdAt: kbCA, updatedAt: kbUA, organizationId: kbOrgId, ...kbData } = devKB;
  const prodKB = await post(PROD_BASE, "/api/knowledge-bases", {
    ...kbData,
    organizationId: PROD_ORG,
  });
  prodIds.kbId = prodKB.id;
  log(`Knowledge Base → ${prodKB.id}`);

  // ── STEP 3: 6 KB SOURCES ─────────────────────────────────────────────────────
  step("3", "11", "Migrating 6 knowledge base sources to PROD");
  prodIds.kbSourceIds = [];
  const devSources = await getDevKBSources(devIds.kbId);
  for (const src of devSources) {
    try {
      const prodSrc = await post(PROD_BASE, `/api/knowledge-bases/${prodIds.kbId}/sources/text`, {
        title: src.title || src.name,
        content: src.content,
        tags: src.tags,
        metadata: src.metadata,
      });
      prodIds.kbSourceIds.push(prodSrc.id);
      log(`KB Source → ${(src.title || src.name || "").slice(0, 65)}`);
    } catch (e) {
      warn(`KB Source (non-fatal): ${(src.title || "").slice(0, 40)} — ${e.message.slice(0, 80)}`);
    }
  }

  // ── STEP 4: 6 RUNBOOKS ───────────────────────────────────────────────────────
  step("4", "11", "Migrating 6 runbooks to PROD");
  prodIds.runbookIds = [];
  for (const devRbId of devIds.runbookIds) {
    const devRb = await getDevRunbook(devRbId);
    const { id, createdAt, updatedAt, agentId, organizationId, ...rbData } = devRb;
    const prodRb = await post(PROD_BASE, "/api/runbooks", {
      ...rbData,
      organizationId: PROD_ORG,
      agentId: null,
    });
    prodIds.runbookIds.push(prodRb.id);
    log(`Runbook → ${devRb.name.slice(0, 60)} [${prodRb.id}]`);
  }

  // ── STEP 5: 6 GOVERNANCE POLICIES ────────────────────────────────────────────
  step("5", "11", "Migrating 6 governance policies to PROD");
  prodIds.policyIds = [];
  for (const devPId of devIds.policyIds) {
    const devPol = await getDevPolicy(devPId);
    const { id, createdAt, updatedAt, scopeId, scopeType, organizationId, ...polData } = devPol;
    const prodPol = await post(PROD_BASE, "/api/policies", {
      ...polData,
      organizationId: PROD_ORG,
    });
    prodIds.policyIds.push(prodPol.id);
    log(`Policy → ${devPol.name.slice(0, 60)} [${prodPol.id}]`);
  }

  // ── STEP 6: AGENT ────────────────────────────────────────────────────────────
  step("6", "11", "Creating agent OTC-AGT-007 in PROD");
  const devAgent = await getDevAgent(devIds.agentId);
  const {
    id: aId, createdAt: aCA, updatedAt: aUA,
    organizationId: aOrg, outcomeId, evalBindings,
    ontologyTags, knowledgeBases, agentKnowledgeBases,
    preloadedSkills: devPreloadedSkills,
    policyBindings: devPolicyBindings,
    ...agentData
  } = devAgent;

  const prodAgent = await post(PROD_BASE, "/api/agents", {
    ...agentData,
    organizationId: PROD_ORG,
    environment: "production",
    preloadedSkills: prodIds.skillIds.map((skillId, i) => ({ skillId, loadOrder: i })),
    policyBindings: prodIds.policyIds,
  });
  prodIds.agentId = prodAgent.id;
  log(`Agent: Delivery Tracking & Confirmation Agent → ${prodAgent.id}`);

  // ── STEP 7: LINK RUNBOOKS & POLICIES ─────────────────────────────────────────
  step("7", "11", "Linking runbooks (agentId) and policies (scopeId) to PROD agent");
  for (const rId of prodIds.runbookIds) {
    try {
      await patch(PROD_BASE, `/api/runbooks/${rId}`, { agentId: prodIds.agentId });
    } catch (e) {
      warn(`Runbook link (non-fatal): ${e.message.slice(0, 60)}`);
    }
  }
  log("All 6 runbooks: agentId set");
  for (const pId of prodIds.policyIds) {
    try {
      await patch(PROD_BASE, `/api/policies/${pId}`, { scopeId: prodIds.agentId, scopeType: "agent" });
    } catch (e) {
      warn(`Policy link (non-fatal): ${e.message.slice(0, 60)}`);
    }
  }
  log("All 6 policies: scopeId set");

  // ── STEP 8: LINK KB TO AGENT ──────────────────────────────────────────────────
  step("8", "11", "Linking knowledge base to PROD agent");
  try {
    await post(PROD_BASE, `/api/agents/${prodIds.agentId}/knowledge-bases`, {
      knowledgeBaseId: prodIds.kbId,
      priority: 1,
      retrievalConfig: {
        topK: 12,
        scoreThreshold: 0.68,
        rerankEnabled: true,
        citationMode: "full",
        carrierFiltering: true,
        milestoneFiltering: true,
        exceptionTypeFiltering: true,
      },
    });
    log(`Knowledge base linked to PROD agent`);
  } catch (e) {
    warn(`KB link (non-fatal): ${e.message.slice(0, 80)}`);
  }

  // ── STEP 9: GOLDEN DATASET + TEST CASES ──────────────────────────────────────
  step("9", "11", "Migrating golden dataset + test cases to PROD");
  const devDS = await getDevDataset(devIds.goldenDatasetId);
  const { id: dsId, createdAt: dsCA, updatedAt: dsUA, organizationId: dsOrg, testCaseCount, ...dsData } = devDS;
  const prodDS = await post(PROD_BASE, "/api/golden-datasets", {
    ...dsData,
    organizationId: PROD_ORG,
  });
  prodIds.goldenDatasetId = prodDS.id;
  log(`Golden Dataset → ${prodDS.id}`);

  prodIds.testCaseIds = [];
  const devTestCases = await getDevTestCases(devIds.goldenDatasetId);
  for (const tc of devTestCases) {
    try {
      const { id: tcId, createdAt: tcCA, updatedAt: tcUA, datasetId, organizationId: tcOrg, ...tcData } = tc;
      const prodTC = await post(PROD_BASE, `/api/golden-datasets/${prodIds.goldenDatasetId}/test-cases`, {
        ...tcData,
        datasetId: prodIds.goldenDatasetId,
      });
      prodIds.testCaseIds.push(prodTC.id);
      log(`Test Case → ${tc.name.slice(0, 65)}`);
    } catch (e) {
      warn(`Test Case (non-fatal): ${tc.name?.slice(0, 40)} — ${e.message.slice(0, 80)}`);
    }
  }

  // ── STEP 10: EVAL SUITE ───────────────────────────────────────────────────────
  step("10", "11", "Creating evaluation suite in PROD");
  const devEval = await getDevEval(devIds.evalSuiteId);
  const { id: evId, createdAt: evCA, updatedAt: evUA, organizationId: evOrg, agentId: evAgent, goldenDatasetId: evDS, ...evalData } = devEval;
  const prodEval = await post(PROD_BASE, "/api/evals", {
    ...evalData,
    organizationId: PROD_ORG,
    agentId: prodIds.agentId,
    goldenDatasetId: prodIds.goldenDatasetId,
  });
  prodIds.evalSuiteId = prodEval.id;
  log(`Eval Suite → ${prodEval.id}`);

  // ── STEP 11: OUTCOME CONTRACT + KPIs ─────────────────────────────────────────
  step("11", "11", "Creating outcome contract + KPIs in PROD and linking all to agent");
  let devKPIs = [];
  try {
    devKPIs = await getDevOutcomeKPIs(devIds.outcomeId);
  } catch (e) {
    warn(`Could not fetch dev KPIs: ${e.message.slice(0, 60)}`);
  }

  const devOutcome = await getDevOutcome(devIds.outcomeId);
  const { id: ocId, createdAt: ocCA, updatedAt: ocUA, organizationId: ocOrg, ...outcomeData } = devOutcome;

  // Clean KPI data for PROD
  const prodKPIs = devKPIs.map(kpi => {
    const { id, createdAt, updatedAt, outcomeId: kpiOC, organizationId: kpiOrg, ...kpiData } = kpi;
    return kpiData;
  });

  const prodOutcome = await post(PROD_BASE, "/api/outcomes/with-kpis", {
    outcome: {
      ...outcomeData,
      organizationId: PROD_ORG,
      attributionRules: {
        ...outcomeData.attributionRules,
        agentId: prodIds.agentId,
      },
    },
    kpis: prodKPIs.length > 0 ? prodKPIs : [
      { name: "On-Time Delivery Rate (OTP)", description: "Percentage of shipments delivered on or before the carrier-committed delivery date, excluding customer-caused delays and weather excused events", type: "performance", targetValue: 96, unit: "percentage", measurementFrequency: "weekly", formula: "(shipments_delivered_on_or_before_committed_date / total_eligible_shipments) * 100", tags: ["OTP", "OTC-AGT-007"] },
      { name: "POD Capture Rate", description: "Percentage of delivered shipments for which a validated electronic proof of delivery record is captured and archived", type: "accuracy", targetValue: 98.5, unit: "percentage", measurementFrequency: "daily", formula: "(shipments_with_validated_pod / total_delivered_shipments) * 100", tags: ["POD", "OTC-AGT-007"] },
      { name: "Delivery Exception Rate", description: "Percentage of total shipments that experience at least one delivery exception requiring customer notification", type: "quality", targetValue: 3.5, unit: "percentage", measurementFrequency: "weekly", formula: "(shipments_with_exceptions / total_shipments) * 100", tags: ["exception-rate", "OTC-AGT-007"] },
      { name: "ETA Prediction Accuracy", description: "Percentage of shipments where actual delivery falls within the predicted ETA window", type: "accuracy", targetValue: 88, unit: "percentage", measurementFrequency: "weekly", formula: "(shipments_delivered_within_eta_window / total_tracked_shipments) * 100", tags: ["ETA-accuracy", "OTC-AGT-007"] },
      { name: "Customer Notification Timeliness Rate", description: "Percentage of delivery milestone events for which the customer notification is sent within the required SLA window", type: "performance", targetValue: 99, unit: "percentage", measurementFrequency: "daily", formula: "(notifications_sent_within_sla / total_notification_triggers) * 100", tags: ["notification-timeliness", "OTC-AGT-007"] },
      { name: "At-Risk Shipment Detection Rate", description: "Percentage of late shipments for which the at-risk flag was raised at least 4 hours before the original committed delivery date", type: "accuracy", targetValue: 85, unit: "percentage", measurementFrequency: "weekly", formula: "(late_shipments_flagged_4h_before_eta / total_late_shipments) * 100", tags: ["at-risk-detection", "OTC-AGT-007"] },
      { name: "Tracking Update Freshness", description: "Percentage of tracking events reflected in the unified tracking system within 2 hours of the carrier recording the event", type: "efficiency", targetValue: 95, unit: "percentage", measurementFrequency: "daily", formula: "(events_reflected_within_2h / total_tracking_events) * 100", tags: ["tracking-freshness", "OTC-AGT-007"] },
      { name: "Carrier SLA Claim Recovery Rate", description: "Percentage of eligible carrier SLA breach claim value successfully recovered through the claims filing program", type: "efficiency", targetValue: 85, unit: "percentage", measurementFrequency: "monthly", formula: "(claim_value_recovered / total_eligible_claim_value) * 100", tags: ["carrier-claims", "OTC-AGT-007"] },
    ],
  });
  prodIds.outcomeId = prodOutcome.outcome?.id || prodOutcome.id;
  log(`Outcome Contract → ${prodIds.outcomeId}`);

  // Link outcome + eval to PROD agent
  await patch(PROD_BASE, `/api/agents/${prodIds.agentId}`, {
    outcomeId: prodIds.outcomeId,
    evalBindings: [prodIds.evalSuiteId],
  });
  log("Outcome contract linked to PROD agent");
  log("Eval suite linked to PROD agent");

  // Ontology tags — fetched dynamically from PROD
  try {
    const allConcepts = await get(PROD_BASE, "/api/ontology-concepts/all");
    const byId = new Map(allConcepts.map(c => [c.id, c]));

    const preferred = ["gs1-10", "gs1-11", "gs1-12", "gs1-13", "isa-25"];
    const tags = [];
    for (const id of preferred) {
      if (byId.has(id)) {
        const c = byId.get(id);
        tags.push({ conceptId: c.id, label: c.label, category: c.category });
      }
    }
    if (tags.length < 5) {
      const used = new Set(tags.map(t => t.conceptId));
      const logisticsKeywords = ["logistic", "delivery", "transport", "shipping", "carrier", "tracking", "fulfillment", "supply", "dispatch", "order"];
      for (const c of allConcepts) {
        if (tags.length >= 6) break;
        if (used.has(c.id)) continue;
        const labelLower = (c.label || "").toLowerCase();
        if (logisticsKeywords.some(kw => labelLower.includes(kw))) {
          tags.push({ conceptId: c.id, label: c.label, category: c.category });
          used.add(c.id);
        }
      }
      if (tags.length < 5) {
        for (const c of allConcepts.filter(x =>
          ["gs1", "isa", "otc"].some(prefix => x.id.startsWith(prefix)) && !used.has(x.id)
        )) {
          if (tags.length >= 6) break;
          tags.push({ conceptId: c.id, label: c.label, category: c.category });
          used.add(c.id);
        }
      }
    }
    await patch(PROD_BASE, `/api/agents/${prodIds.agentId}`, { ontologyTags: tags });
    log(`Ontology tags set (${tags.length}): ${tags.map(t => t.label).join(", ")}`);
  } catch (e) {
    warn(`Ontology tags (non-fatal): ${e.message.slice(0, 100)}`);
  }

  // ── SAVE PROD IDs ─────────────────────────────────────────────────────────────
  writeFileSync("scripts/otc-agt-007-prod-ids.json", JSON.stringify(prodIds, null, 2));

  console.log("\n════════════════════════════════════════════════════════════════════");
  console.log("  ✅  OTC-AGT-007 — PROD MIGRATION COMPLETE");
  console.log("════════════════════════════════════════════════════════════════════");
  console.log(`\n  PROD Agent:          ${prodIds.agentId}`);
  console.log(`  PROD Knowledge Base: ${prodIds.kbId} (${prodIds.kbSourceIds?.length || 0} sources)`);
  console.log(`  PROD Skills (6):     ${prodIds.skillIds.join(", ")}`);
  console.log(`  PROD Policies (6):   ${prodIds.policyIds.join(", ")}`);
  console.log(`  PROD Runbooks (6):   ${prodIds.runbookIds.join(", ")}`);
  console.log(`  PROD Dataset:        ${prodIds.goldenDatasetId} (${prodIds.testCaseIds?.length || 0} test cases)`);
  console.log(`  PROD Eval Suite:     ${prodIds.evalSuiteId}`);
  console.log(`  PROD Outcome:        ${prodIds.outcomeId}`);
  console.log(`\n  Prod IDs saved → scripts/otc-agt-007-prod-ids.json\n`);
}

main().catch(err => {
  console.error(`\n❌  PROD migration failed: ${err.message}`);
  process.exit(1);
});
